#include <stdio.h>

long countWaysToMakeChangeUtil(int* arr, int ind, int T, long** dp) {
    if (ind == 0) {
        return (T % arr[0] == 0) ? 1 : 0;
    }
    if (dp[ind][T] != -1) return dp[ind][T];

    long notTaken = countWaysToMakeChangeUtil(arr, ind - 1, T, dp);
    long taken = 0;
    if (arr[ind] <= T) {
        taken = countWaysToMakeChangeUtil(arr, ind, T - arr[ind], dp);
    }
    dp[ind][T] = notTaken + taken;
    return dp[ind][T];
}

long countWaysToMakeChange(int* arr, int n, int T) {
    long** dp = (long**)malloc(n * sizeof(long*));
    for (int i = 0; i < n; i++) {
        dp[i] = (long*)malloc((T + 1) * sizeof(long));
        for (int j = 0; j <= T; j++) {
            dp[i][j] = -1;
        }
    }
    return countWaysToMakeChangeUtil(arr, n - 1, T, dp);
}

int main() {
    int n;
    scanf("%d", &n);
    int* arr = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int T;
    scanf("%d", &T);
    printf("%ld\n", countWaysToMakeChange(arr, n, T));
    return 0;
}

