class Solution {
    // Recursive function with memoization
    countWaysToMakeChangeUtil(arr, ind, T, dp) {
        if (ind === 0) {
            return (T % arr[0] === 0) ? 1 : 0;
        }
        if (dp[ind][T] !== -1) return dp[ind][T];

        let notTaken = this.countWaysToMakeChangeUtil(arr, ind - 1, T, dp);
        let taken = 0;
        if (arr[ind] <= T) {
            taken = this.countWaysToMakeChangeUtil(arr, ind, T - arr[ind], dp);
        }
        dp[ind][T] = notTaken + taken;
        return dp[ind][T];
    }

    countWaysToMakeChange(arr, n, T) {
        const dp = Array.from({ length: n }, () => Array(T + 1).fill(-1));
        return this.countWaysToMakeChangeUtil(arr, n - 1, T, dp);
    }
}

